function RecipeSearch() {
  const [query, setQuery] = React.useState('REPLACE_WITH_INGREDIENT');
  const [recipes, setRecipes] = React.useState([]);
  const [selected, setSelected] = React.useState(null);
  const [loading, setLoading] = React.useState(false);

  const search = () => {
    if (!query.trim()) return;
    setLoading(true);
    setSelected(null);
    fetch(`https://www.themealdb.com/api/json/v1/1/search.php?s=${encodeURIComponent(query)}`)
      .then(r=>r.json())
      .then(d=>{setRecipes(d.meals||[]);setLoading(false);})
      .catch(()=>setLoading(false));
  };

  const getIngredients = (meal) => {
    const out = [];
    for (let i=1;i<=20;i++){
      const ing = meal[`strIngredient${i}`];
      const meas = meal[`strMeasure${i}`];
      if (ing && ing.trim()) out.push(`${meas||''} ${ing}`.trim());
    }
    return out;
  };

  return (
    <div style={{padding:16,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column'}}>
      <div style={{fontSize:18,fontWeight:700,marginBottom:12}}>Recipe Search</div>
      <div style={{display:'flex',gap:8,marginBottom:12}}>
        <input value={query} onChange={e=>setQuery(e.target.value)} onKeyDown={e=>e.key==='Enter'&&search()}
          style={{flex:1,padding:'8px 12px',borderRadius:8,border:'1px solid #ccc',fontSize:14}}
          placeholder="Dish or ingredient…"/>
        <button onClick={search}
          style={{padding:'8px 16px',borderRadius:8,background:'#007AFF',color:'#fff',border:'none',cursor:'pointer'}}>
          Search
        </button>
      </div>
      {loading && <div style={{textAlign:'center',color:'#888'}}>Loading…</div>}
      {selected ? (
        <div style={{flex:1,overflow:'auto'}}>
          <button onClick={()=>setSelected(null)} style={{marginBottom:12,background:'none',border:'none',color:'#007AFF',cursor:'pointer',fontSize:14}}>← Back</button>
          <img src={selected.strMealThumb} style={{width:'100%',height:180,objectFit:'cover',borderRadius:12,marginBottom:12}}/>
          <div style={{fontSize:20,fontWeight:700,marginBottom:8}}>{selected.strMeal}</div>
          <div style={{color:'#888',fontSize:13,marginBottom:12}}>{selected.strArea} • {selected.strCategory}</div>
          <div style={{fontSize:14,fontWeight:600,marginBottom:6}}>Ingredients</div>
          <ul style={{margin:0,paddingLeft:20,fontSize:13,color:'#444',marginBottom:16}}>
            {getIngredients(selected).map((ing,i)=><li key={i}>{ing}</li>)}
          </ul>
          <div style={{fontSize:14,fontWeight:600,marginBottom:6}}>Instructions</div>
          <div style={{fontSize:13,lineHeight:1.6,color:'#444',whiteSpace:'pre-line'}}>{selected.strInstructions}</div>
        </div>
      ) : (
        <div style={{flex:1,overflow:'auto',display:'grid',gridTemplateColumns:'repeat(2,1fr)',gap:10}}>
          {recipes.map(r=> (
            <div key={r.idMeal} onClick={()=>setSelected(r)}
              style={{cursor:'pointer',borderRadius:10,overflow:'hidden',background:'#f5f5f5'}}>
              <img src={r.strMealThumb} style={{width:'100%',height:100,objectFit:'cover'}}/>
              <div style={{padding:8,fontSize:13,fontWeight:600}}>{r.strMeal}</div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
render(<RecipeSearch/>);
